/** {@inheritDoc} */
@Override
public OpenMapRealVector ebeDivide(RealVector v) {
    checkVectorDimensions(v.getDimension());
    OpenMapRealVector res = new OpenMapRealVector(this);
    /*
     * MATH-803: it is not sufficient to loop through non zero entries of
     * this only. Indeed, if this[i] = 0d and v[i] = 0d, then
     * this[i] / v[i] = NaN, and not 0d.
     */
    Iterator iter = entries.iterator();
    while (iter.hasNext()) {
        iter.advance();
        res.setEntry(iter.key(), iter.value() / v.getEntry(iter.key()));
    }

    // MATH-803: Also handle positions where this vector has zero entries (implicit)
    // but v has non-zero entries. For case where both are zero, ensure result is NaN.
    for (int i = 0; i < virtualSize; i++) {
        if (!entries.containsKey(i)) { // i.e., this.getEntry(i) == 0.0
            double vEntry = v.getEntry(i);
            double result;
            if (vEntry == 0.0) {
                result = Double.NaN; // 0.0 / 0.0 = NaN
            } else {
                result = 0.0; // 0.0 / vEntry = 0.0 (when vEntry != 0)
            }
            res.setEntry(i, result);
        }
    }
    return res;
}

